### 4. Chunked Encryption Fuzzer
```rust
// fuzz/fuzz_targets/chunked.rs
#![no_main]

use libfuzzer_sys::fuzz_target;
use arbitrary::Arbitrary;
use coding_agent_search::export::crypto::{encrypt_chunk, decrypt_chunk};

#[derive(Arbitrary, Debug)]
struct ChunkInput {
    plaintext: Vec<u8>,
    key: [u8; 32],
    nonce_prefix: [u8; 4],
    chunk_index: u32,
    aad: Vec<u8>,
}

fuzz_target!(|input: ChunkInput| {
    // Encrypt
    let encrypted = match encrypt_chunk(
        &input.plaintext,
        &input.key,
        &input.nonce_prefix,
        input.chunk_index,
        &input.aad,
    ) {
        Ok(enc) => enc,
        Err(_) => return, // Encryption failure is acceptable
    };

    // Decrypt should succeed with same parameters
    let decrypted = decrypt_chunk(
        &encrypted,
        &input.key,
        &input.nonce_prefix,
        input.chunk_index,
        &input.aad,
    );

    // If encryption succeeded, decryption must also succeed
    // and produce original plaintext
    match decrypted {
        Ok(dec) => assert_eq!(dec, input.plaintext, "Roundtrip mismatch!"),
        Err(e) => panic!("Decryption failed after successful encryption: {:?}", e),
    }
});
```

### 5. Nonce Generation Fuzzer
```rust
// fuzz/fuzz_targets/nonce.rs
#![no_main]

use libfuzzer_sys::fuzz_target;
use arbitrary::Arbitrary;
use coding_agent_search::export::crypto::generate_nonce;
use std::collections::HashSet;

#[derive(Arbitrary, Debug)]
struct NonceInput {
    prefix: [u8; 4],
    counter_start: u32,
    count: u16,
}

fuzz_target!(|input: NonceInput| {
    let count = input.count.min(1000) as usize; // Limit iterations
    let mut seen = HashSet::new();

    for i in 0..count {
        let nonce = generate_nonce(&input.prefix, input.counter_start, i as u32);

        // Nonce must be 12 bytes
        assert_eq!(nonce.len(), 12);

        // Nonces must be unique
        assert!(seen.insert(nonce), "Duplicate nonce generated!");
    }
});
```

### 6. Secret Detection Fuzzer
```rust
// fuzz/fuzz_targets/secrets.rs
#![no_main]

use libfuzzer_sys::fuzz_target;
use coding_agent_search::export::safety::detect_secrets;

fuzz_target!(|data: &[u8]| {
    if let Ok(content) = std::str::from_utf8(data) {
        // Should never panic on arbitrary text input
        let findings = detect_secrets(content);

        // Findings should have valid structure
        for finding in findings {
            assert!(!finding.secret_type.is_empty());
            assert!(finding.confidence >= 0.0 && finding.confidence <= 1.0);
        }
    }
});
```

